import{_ as t,o as e,c as r,ae as o}from"./chunks/framework.Czhw_PXq.js";const p=JSON.parse('{"title":"连接设备","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/guide/connect.md","filePath":"zh-cn/guide/connect.md"}'),d={name:"zh-cn/guide/connect.md"};function i(n,a,l,h,c,s){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="连接设备" tabindex="-1">连接设备 <a class="header-anchor" href="#连接设备" aria-label="Permalink to &quot;连接设备&quot;">​</a></h1><h2 id="添加新设备" tabindex="-1">添加新设备 <a class="header-anchor" href="#添加新设备" aria-label="Permalink to &quot;添加新设备&quot;">​</a></h2><ol><li>点击设备下拉框底部的「添加设备」</li><li>输入设备 IP 地址和端口号</li><li>点击「连接」</li></ol><p><strong>常见端口</strong>：<code>5555</code>（ADB WiFi 默认端口）</p><h2 id="连接状态说明" tabindex="-1">连接状态说明 <a class="header-anchor" href="#连接状态说明" aria-label="Permalink to &quot;连接状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态图标</th><th>含义</th></tr></thead><tbody><tr><td>🟢 绿点</td><td>设备已连接，可执行截图</td></tr><tr><td>⚪ 灰点</td><td>设备离线，未连接</td></tr><tr><td>🔴 红点</td><td>连接失败</td></tr></tbody></table><h2 id="批量连接" tabindex="-1">批量连接 <a class="header-anchor" href="#批量连接" aria-label="Permalink to &quot;批量连接&quot;">​</a></h2><p>启动应用时，会自动探测最近连接过的设备的在线状态（无数量限制）。</p><h2 id="断开设备" tabindex="-1">断开设备 <a class="header-anchor" href="#断开设备" aria-label="Permalink to &quot;断开设备&quot;">​</a></h2><p>点击已连接设备旁边的「×」按钮可断开连接并从列表移除。</p><h2 id="自动重连" tabindex="-1">自动重连 <a class="header-anchor" href="#自动重连" aria-label="Permalink to &quot;自动重连&quot;">​</a></h2><p>当设备离线后重新上线，点击截图时会自动尝试连接，无需手动重新添加。</p><h2 id="截图时自动连接" tabindex="-1">截图时自动连接 <a class="header-anchor" href="#截图时自动连接" aria-label="Permalink to &quot;截图时自动连接&quot;">​</a></h2><p>当点击截图按钮时，如果目标设备不在连接列表中，会自动尝试连接该设备。无需手动添加设备即可直接截图。</p>',14)])])}const _=t(d,[["render",i]]);export{p as __pageData,_ as default};
